export function flattedData(data: ContentNavigationItem[]) {
  const flatData = data.flatMap((item) => {
    const children: ContentNavigationItem[] = item.children ? flattedData(item.children) : []
    if (item.page === false || (children.length && children.find(c => c.path === item.path))) {
      return children
    }

    return [{ ...item, children: undefined }, ...children]
  })

  return flatData
}

function filter(item: Import) {
  if (item.type)
    return false
  const name = item.as || item.name
  if (!include.some(f => typeof f === 'function' ? f(item) : typeof f === 'string' ? name === f : f.test(name)))
    return false
  if (exclude.some(f => typeof f === 'function' ? f(item) : typeof f === 'string' ? name === f : f.test(name)))
    return false
  return true
}

export async function resolveFiles (path: string, pattern: string | string[], opts: { followSymbolicLinks?: boolean, ignore?: GlobOptions['ignore'] } = {}): Promise<string[]> {
  const files: string[] = []
  for (const p of await glob(pattern, { cwd: path, followSymbolicLinks: opts.followSymbolicLinks ?? true, absolute: true, ignore: opts.ignore })) {
    if (!isIgnored(p)) {
      files.push(p)
    }
  }
  return files.sort()
}

const fields = computed(() => {
  // @ts-expect-error ignore {} not assignable to object
